import React, { useState, useEffect } from 'react';
import { Task } from './types';
import { getTasks, createTask, toggleTask, deleteTask } from './api';
import './App.css';

const App: React.FC = () => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [input, setInput] = useState<string>('');
  const [error, setError] = useState<string>('');
  const [loading, setLoading] = useState<boolean>(true);
  const [adding, setAdding] = useState<boolean>(false);

  // Fetch tasks on load
  useEffect(() => {
    fetchTasks();
  }, []);

  const fetchTasks = async () => {
    try {
      const data = await getTasks();
      setTasks(data);
    } catch {
      setError('Could not connect to server. Make sure backend is running.');
    } finally {
      setLoading(false);
    }
  };

  const handleAdd = async () => {
    if (input.trim() === '') {
      setError('Task title is required!');
      return;
    }
    setError('');
    setAdding(true);
    try {
      const newTask = await createTask(input.trim());
      setTasks([...tasks, newTask]);
      setInput('');
    } catch {
      setError('Failed to add task.');
    } finally {
      setAdding(false);
    }
  };

  const handleToggle = async (id: number) => {
    try {
      const updated = await toggleTask(id);
      setTasks(tasks.map((t) => (t.id === id ? updated : t)));
    } catch {
      setError('Failed to update task.');
    }
  };

  const handleDelete = async (id: number) => {
    try {
      await deleteTask(id);
      setTasks(tasks.filter((t) => t.id !== id));
    } catch {
      setError('Failed to delete task.');
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') handleAdd();
  };

  const completed = tasks.filter((t) => t.completed).length;
  const pending = tasks.length - completed;
  const progress = tasks.length > 0 ? (completed / tasks.length) * 100 : 0;

  return (
    <div className="app">
      <div className="container">
        {/* Header */}
        <div className="header">
          <div className="header-top">
            <span className="logo">✦</span>
            <h1>TaskFlow</h1>
          </div>
          <p className="subtitle">Stay organized, stay ahead</p>
        </div>

        {/* Stats */}
        <div className="stats">
          <div className="stat-card completed-card">
            <span className="stat-number">{completed}</span>
            <span className="stat-label">Completed</span>
          </div>
          <div className="stat-card pending-card">
            <span className="stat-number">{pending}</span>
            <span className="stat-label">Pending</span>
          </div>
          <div className="stat-card total-card">
            <span className="stat-number">{tasks.length}</span>
            <span className="stat-label">Total</span>
          </div>
        </div>

        {/* Progress Bar */}
        {tasks.length > 0 && (
          <div className="progress-section">
            <div className="progress-label">
              <span>Progress</span>
              <span>{Math.round(progress)}%</span>
            </div>
            <div className="progress-bar">
              <div className="progress-fill" style={{ width: `${progress}%` }} />
            </div>
          </div>
        )}

        {/* Input */}
        <div className="input-section">
          <input
            type="text"
            value={input}
            onChange={(e) => {
              setInput(e.target.value);
              setError('');
            }}
            onKeyDown={handleKeyDown}
            placeholder="Add a new task..."
            className={`task-input ${error ? 'input-error' : ''}`}
            disabled={adding}
          />
          <button onClick={handleAdd} className="add-btn" disabled={adding}>
            {adding ? '...' : '+'}
          </button>
        </div>
        {error && <p className="error-msg">⚠ {error}</p>}

        {/* Task List */}
        <div className="task-list">
          {loading ? (
            <div className="empty-state">
              <span>Loading tasks...</span>
            </div>
          ) : tasks.length === 0 ? (
            <div className="empty-state">
              <span className="empty-icon">📋</span>
              <p>No tasks yet. Add one above!</p>
            </div>
          ) : (
            tasks.map((task) => (
              <div key={task.id} className={`task-item ${task.completed ? 'task-done' : ''}`}>
                <button
                  className={`check-btn ${task.completed ? 'checked' : ''}`}
                  onClick={() => handleToggle(task.id)}
                >
                  {task.completed ? '✓' : ''}
                </button>
                <span className="task-title">{task.title}</span>
                <button className="delete-btn" onClick={() => handleDelete(task.id)}>
                  ✕
                </button>
              </div>
            ))
          )}
        </div>

        {tasks.length > 0 && completed === tasks.length && (
          <div className="all-done">
            🎉 All tasks completed! Great job!
          </div>
        )}
      </div>
    </div>
  );
};

export default App;
